145	------------------------------------------------------------------------------
146	-- Package Body
147	------------------------------------------------------------------------------
148	package body psi_tb_i2c_pkg is
149	
150		-- -----------------------------------------------------------------------
151		-- Local Types
152		-- -----------------------------------------------------------------------
153		type MsgInfo_r is record
154			Prefix	: string;
155			Func	: string;
156			User	: string;
157		end record;
158	
159		-- -----------------------------------------------------------------------
160		-- Local Variables
161		-- -----------------------------------------------------------------------
162		shared variable FreqClk_v	: real	:= 100.0e3;
163	
164		-- -----------------------------------------------------------------------
165		-- Private Procedures
166		-- -----------------------------------------------------------------------
167		-- *** Message Handling ***
168		function GenMessage(	Prefix	: in string;
169								Func 	: in string;
170								General	: in string;
171								User	: in string) 
172								return string is
173		begin
174			return Prefix & "- " & Func & " - " & General & " - " & User;
175		end function;
176		
177		function GenMessageNoPrefix(	Func 	: in string;
178										General	: in string;
179										User	: in string) 
180										return string is	
181		begin
182			return Func & " - " & General & " - " & User;
183		end function;
184		
185		-- *** Level Check ***
186		procedure LevelCheck(	Expected	: in	std_logic;
187								signal Sig	: in	std_logic;
188								Msg			: in	MsgInfo_r;
189								GeneralMsg	: in	string) is
190		begin
191			-- Do not check for other inputs than 1 or 0
192			if (Expected = '0') or (Expected = '1') then
193				assert ((Expected = '0') and (Sig = '0')) or ((Expected = '1') and ((Sig = '1') or (Sig = 'H')))
194					report GenMessage(Msg.Prefix, Msg.Func, GeneralMsg, Msg.User)
195					severity error;
196			end if;
197		end procedure;
198		
199		procedure LevelWait(	Expected	: in	std_logic;
200								signal Sig	: in	std_logic;
201								Timeout		: in	time;
202								Msg			: in	MsgInfo_r;
203								GeneralMsg	: in	string) is
204			variable Correct_v : boolean;
205		begin
206			if Sig /= Expected then
207				if Expected = '0' then
208					wait until Sig = '0' for Timeout;
209					Correct_v := (Sig = '0');
210				else
211					wait until (Sig = '1') or (Sig = 'H') for Timeout;
212					Correct_v := ((Sig = '1') or (Sig = 'H'));
213				end if;
214				assert Correct_v 
215					report GenMessage(Msg.Prefix, Msg.Func, GeneralMsg, Msg.User)
216					severity error;
217			end if;
218		end procedure;
219		
220		
221		-- *** Time Calculations ***
222		impure function ClkPeriod return time is
223		begin
224			return (1 sec) / FreqClk_v;
225		end function;
226		
227		impure function ClkHalfPeriod return time is
228		begin
229			return (0.5 sec) / FreqClk_v;
230		end function;	
231		
232		impure function ClkQuartPeriod return time is
233		begin
234			return (0.25 sec) / FreqClk_v;
235		end function;		
236		
237		-- *** Bit Transfers ***
238		procedure SendBitInclClock(	Data		: in	std_logic;
239									signal Scl	: inout std_logic;
240									signal Sda	: inout std_logic;
241									BitInfo		: in	string;
242									Msg			: in 	MsgInfo_r) is
243		begin
244			-- Initial Check
245			LevelCheck('0', Scl, Msg, "SCL must be 0 before SendBitInclClock is called [" & BitInfo & "]");
246			
247			-- Assert Data		
248			if Data = '0' then
249				Sda <= '0';
250			else
251				Sda <= 'Z';
252			end if;
253			wait for ClkQuartPeriod;
254			
255			-- Send Clk Pulse
256			Scl <= 'Z';
257			LevelWait('1', Scl, 1 ms, Msg, "SCL held low by other device");
258			wait for ClkHalfPeriod;
259			CheckLastActivity(Scl, ClkHalfPeriod*0.9, -1, GenMessageNoPrefix(Msg.Func, "SCL high period too short [" & BitInfo & "]", Msg.User), Msg.Prefix);
260			LevelCheck(Data, Sda, Msg, "SDA readback does not match SDA transmit value during SCL pulse [" & BitInfo & "]");
261			CheckLastActivity(Sda, ClkHalfPeriod, -1, GenMessageNoPrefix(Msg.Func, "SDA not stable during SCL pulse [" & BitInfo & "]", Msg.User), Msg.Prefix);
262			Scl <= '0';
263			wait for ClkQuartPeriod;	
264		end procedure;
265		
266		procedure CheckBitInclClock(	Data			: in	std_logic;
267										signal Scl		: inout std_logic;
268										signal Sda		: inout std_logic;
269										BitInfo			: in	string;
270										Msg				: in 	MsgInfo_r) is	
271		begin
272			-- Initial Check
273			LevelCheck('0', Scl, Msg, "SCL must be 0 before CheckBitInclClock is called");
274			
275			-- Wait for assertion
276			wait for ClkQuartPeriod;
277			
278			-- Send Clk Pulse
279			Scl <= 'Z';
280			LevelWait('1', Scl, 1 ms, Msg, "SCL held low by other device");
281			wait for ClkHalfPeriod;
282			CheckLastActivity(Scl, ClkHalfPeriod*0.9, -1, GenMessageNoPrefix(Msg.Func, "SCL high period too short [" & BitInfo & "]", Msg.User), Msg.Prefix);
283			LevelCheck(Data, Sda, Msg, "Received wrong data [" & BitInfo & "]");
284			CheckLastActivity(Sda, ClkHalfPeriod, -1, GenMessageNoPrefix(Msg.Func, "SDA not stable during SCL pulse [" & BitInfo & "]", Msg.User), Msg.Prefix);
285			Scl <= '0';
286			wait for ClkQuartPeriod;	
287		end procedure;	
288		
289		procedure SendBitExclClock(		Data			: in	std_logic;
290										signal Scl		: inout std_logic;
291										signal Sda		: inout std_logic;
292										Timeout			: in	time;
293										BitInfo			: in	string;
294										Msg				: in 	MsgInfo_r;
295										ClockStretch	: in	time) is	
296			variable Stretched_v : boolean := false;
297		begin
298			-- Initial Check
299			LevelCheck('0', Scl, Msg, "SCL must be 0 before SendBitExclClock is called");
300			
301			-- Clock stretching
302			if ClockStretch > 0 ns then
303				Scl <= '0';
304				wait for ClockStretch;
305				Stretched_v := true;
306			end if;
307			
308			-- Assert Data		
309			if Data = '0' then
310				Sda <= '0';
311			else
312				Sda <= 'Z';
313			end if;	
314			if Stretched_v then
315				wait for ClkQuartPeriod;
316				Scl <= 'Z';
317			end if;
318			
319			-- Wait clock rising edge
320			LevelWait('1', Scl, Timeout, Msg, "SCL did not go high");
321			
322			-- wait clock falling edge
323			LevelWait('0', Scl, Timeout, Msg, "SCL did not go low");
324			LevelCheck(Data, Sda, Msg, "Received wrong data [" & BitInfo & "]");
325			CheckLastActivity(Sda, ClkHalfPeriod, -1, GenMessageNoPrefix(Msg.Func, "SDA not stable during SCL pulse [" & BitInfo & "]", Msg.User), Msg.Prefix);
326			
327			-- wait until center of low
328			wait for ClkQuartPeriod;
329		end procedure;		
330		
331		procedure CheckBitExclClock(	Data			: in	std_logic;
332										signal Scl		: inout std_logic;
333										signal Sda		: inout std_logic;
334										Timeout			: in	time;
335										BitInfo			: in	string;
336										Msg				: in 	MsgInfo_r;
337										ClockStretch	: in	time) is	
338		begin
339			-- Initial Check
340			LevelCheck('0', Scl, Msg, "SCL must be 0 before CheckBitExclClock is called");
341			
342			-- Wait clock rising edge
343			if ClockStretch > 0 ns then
344				Scl <= '0';
345				wait for ClockStretch;
346				Scl <= 'Z';
347			end if;		
348			LevelWait('1', Scl, Timeout, Msg, "SCL did not go high");
349			
350			-- wait clock falling edge
351			LevelWait('0', Scl, Timeout, Msg, "SCL did not go low");
352			LevelCheck(Data, Sda, Msg, "Received wrong data [" & BitInfo & "]");
353			CheckLastActivity(Sda, ClkHalfPeriod, -1, GenMessageNoPrefix(Msg.Func, "SDA not stable during SCL pulse [" & BitInfo & "]", Msg.User), Msg.Prefix);
354			
355			-- wait until center of low
356			wait for ClkQuartPeriod;
357		end procedure;	
358		
359		
360		-- *** Byte Transfers ***	
361		procedure SendByteInclClock(	Data 		: in	std_logic_vector(7 downto 0);
362										signal Scl	: inout std_logic;
363										signal Sda	: inout std_logic;
364										Msg			: in 	MsgInfo_r) is
365		begin
366			-- Do bits
367			for i in 7 downto 0 loop
368				SendBitInclClock(Data(i), Scl, Sda, to_string(i), Msg);		
369			end loop;
370		end procedure;
371	
372	
373		
374		procedure ExpectByteExclClock(	ExpData 	: in	std_logic_vector(7 downto 0);
375										signal Scl	: inout std_logic;
376										signal Sda	: inout std_logic;
377										Msg			: in 	MsgInfo_r;
378										Timeout		: in	time;
379										ClkStretch	: in	time) is
380		begin
381			-- Do bits
382			for i in 7 downto 0 loop
383				CheckBitExclClock(ExpData(i), Scl, Sda, Timeout, to_string(i), Msg, ClkStretch);	
384			end loop;
385		end procedure;
386		
387		-- -----------------------------------------------------------------------
388		-- Functions
389		-- -----------------------------------------------------------------------
390		function I2cGetAddr( Addr 	: in integer;
391							 Trans 	: in I2c_Transaction_t) return integer is
392		begin
393			return Addr*2+choose(Trans=I2c_READ, 1, 0);
394		end function;
395		
396		-- -----------------------------------------------------------------------
397		-- Master Side Transactions
398		-- -----------------------------------------------------------------------
399		procedure I2cPullup(signal Scl : inout std_logic;
400							signal Sda : inout std_logic) is
401		begin
402			Scl <= 'H';
403			Sda <= 'H';
404		end procedure;
405		
406		procedure I2cBusFree(	signal Scl : inout std_logic;
407								signal Sda : inout std_logic) is
408		begin
409			Scl <= 'Z';
410			Sda <= 'Z';
411		end procedure;	
412		
413		procedure I2cSetFrequency(	FrequencyHz	: in	real) is
414		begin
415			FreqClk_v := FrequencyHz;
416		end procedure;
417		
418		procedure I2cMasterSendStart(	signal Scl 	: inout std_logic;
419										signal Sda 	: inout std_logic;
420										Msg			: in 	string	:= "No Msg";
421										Prefix		: in 	string	:= "###ERROR###: ") is
422			constant MsgInfo : MsgInfo_r := (Prefix, "I2cMasterSendStart", Msg);
423		begin
424			-- Initial check
425			LevelCheck('1', Scl, MsgInfo, "SCL must be 1 before procedure is called");
426			LevelCheck('1', Sda, MsgInfo, "SDA must be 1 before procedure is called");
427			
428			-- Do start condition
429			wait for ClkQuartPeriod;
430			Sda <= '0';
431			LevelCheck('1', Scl, MsgInfo, "SCL must be 1 during SDA falling edge");
432			wait for ClkQuartPeriod;
433			
434			-- Go to center of clk low period
435			Scl <= '0';
436			wait for ClkQuartPeriod;
437		end procedure;
438		
439		procedure I2cMasterSendRepeatedStart(	signal Scl 	: inout std_logic;
440												signal Sda 	: inout std_logic;
441												Msg			: in 	string	:= "No Msg";
442												Prefix		: in 	string	:= "###ERROR###: ") is
443			constant MsgInfo : MsgInfo_r := (Prefix, "I2cMasterSendRepeatedStart", Msg);
444		begin
445			-- Initial check
446			if to_01X(Scl) = '1' then
447				LevelCheck('1', Sda, MsgInfo, "SDA must be 1 before procedure is called if SCL = 1");
448			end if;
449			
450			-- Do repeated start
451			if Scl = '0' then
452				Sda <= 'Z';
453				wait for ClkQuartPeriod;
454				LevelCheck('1', Sda, MsgInfo, "SDA held low by other device");
455				Scl <= 'Z';
456				wait for ClkQuartPeriod;
457				LevelCheck('1', Scl, MsgInfo, "SCL held low by other device");
458			end if;
459			wait for ClkQuartPeriod;
460			Sda <= '0';
461			LevelCheck('1', Scl, MsgInfo, "SCL must be 1 during SDA falling edge");
462			wait for ClkQuartPeriod;
463			
464			-- Go to center of clk low period
465			Scl <= '0';
466			wait for ClkQuartPeriod;
467		end procedure;
468										
469		procedure I2cMasterSendStop(	signal Scl 	: inout std_logic;
470										signal Sda 	: inout std_logic;
471										Msg			: in 	string	:= "No Msg";
472										Prefix		: in 	string	:= "###ERROR###: ") is
473			constant MsgInfo : MsgInfo_r := (Prefix, "I2cMasterSendStop", Msg);
474		begin
475			-- Initial check
476			if to_01X(Scl) = '1' then
477				LevelCheck('0', Sda, MsgInfo, "SDA must be 0 before procedure is called if SCL = 1");
478			end if;
479			
480			-- Do stop
481			if Scl = '0' then
482				Sda <= '0';
483				wait for ClkQuartPeriod;
484				Scl <= 'Z';
485				wait for ClkQuartPeriod;
486				LevelCheck('1', Scl, MsgInfo, "SCL held low by other device");
487			else
488				wait for ClkQuartPeriod;		
489			end if;
490			Sda <= 'Z';
491			LevelCheck('1', Scl, MsgInfo, "SCL must be 1 during SDA rising edge");
492			
493			-- Go to center of clk high period
494			wait for ClkQuartPeriod;
495			
496		end procedure;
497								
498		procedure I2cMasterSendAddr(	Address 	: in	integer;
499										IsRead		: in	boolean;
500										signal Scl	: inout std_logic;
501										signal Sda	: inout std_logic;
502										Msg			: in 	string		:= "No Msg";
503										AddrBits	: in	integer		:= 7;		-- 7 or 10
504										ExpectedAck	: in 	std_logic	:= '0';		-- '0' for ack, '1' for nack, anything else for "don't check"
505										Prefix		: in 	string		:= "###ERROR###: ") is	
506			constant AddrSlv_c 	: std_logic_vector(9 downto 0) := std_logic_vector(to_unsigned(Address, 10));
507			constant Rw_c 		: std_logic		:= choose(IsRead, '1', '0');
508		begin
509			-- 7 Bit addressing
510			if AddrBits = 7 then
511				SendByteInclClock(AddrSlv_c(6 downto 0) & Rw_c, Scl, Sda, (Prefix, "I2cMasterSendAddr 7b", Msg));
512				Sda <= 'Z';
513				CheckBitInclClock(ExpectedAck, Scl, Sda, "ACK", (Prefix, "I2cMasterSendAddr 7b", Msg));
514			-- 10 Bit addressing
515			elsif AddrBits = 10 then
516				SendByteInclClock("11110" & AddrSlv_c(9 downto 8) & Rw_c, Scl, Sda, (Prefix, "I2cMasterSendAddr 10b 9:8", Msg));
517				Sda <= 'Z';
518				CheckBitInclClock(ExpectedAck, Scl, Sda, "ACK", (Prefix, "I2cMasterSendAddr 10b 9:8", Msg));
519				SendByteInclClock(AddrSlv_c(7 downto 0), Scl, Sda, (Prefix, "I2cMasterSendAddr 10b 7:0", Msg));
520				Sda <= 'Z';
521				CheckBitInclClock(ExpectedAck, Scl, Sda, "ACK", (Prefix, "I2cMasterSendAddr 10b 7:0", Msg));
522			else
523				report Prefix & "I2cMasterSendAddr - Illegal addrBits (must be 7 or 10) - " & Msg severity error;
524			end if;
525		end procedure;
526									
527		procedure I2cMasterSendByte(	Data 		: in	integer range -128 to 255;
528										signal Scl	: inout std_logic;
529										signal Sda	: inout std_logic;
530										Msg			: in 	string		:= "No Msg";
531										ExpectedAck	: in 	std_logic	:= '0';		-- '0' for ack, '1' for nack, anything else for "don't check"
532										Prefix		: in 	string		:= "###ERROR###: ") is	
533			variable DataSlv_v : std_logic_vector(7 downto 0);
534		begin
535			-- Do data
536			if Data < 0 then
537				DataSlv_v := std_logic_vector(to_signed(Data, 8));
538			else
539				DataSlv_v := std_logic_vector(to_unsigned(Data, 8));
540			end if;
541			SendByteInclClock(DataSlv_v, Scl, Sda, (Prefix, "I2cMasterSendByte", Msg));
542			Sda <= 'Z';
543			CheckBitInclClock(ExpectedAck, Scl, Sda, "ACK", (Prefix, "I2cMasterSendByte", Msg));			
544		end procedure;
545	
546									
547		procedure I2cMasterExpectByte(	ExpData		: in	integer range -128 to 255;
548										signal Scl	: inout std_logic;
549										signal Sda	: inout std_logic;
550										Msg			: in 	string		:= "No Msg";
551										AckOutput	: in 	std_logic	:= '0';		-- '0' for ack, '1' for nack	
552										Prefix		: in 	string		:= "###ERROR###: ") is
553			variable Data_v 	: std_logic_vector(7 downto 0);
554		begin
555			-- Convert data
556			if ExpData < 0 then
557				Data_v := std_logic_vector(to_signed(ExpData, 8));
558			else
559				Data_v := std_logic_vector(to_unsigned(ExpData, 8));
560			end if;
561		
562			-- do bits
563			Sda <= 'Z';
564			for i in 7 downto 0 loop
565				CheckBitInclClock(Data_v(i), Scl, Sda, to_string(i), (Prefix, "I2cMasterExpectByte", Msg));
566			end loop;
567			SendBitInclClock(AckOutput, Scl, Sda, "ACK", (Prefix, "I2cMasterExpectByte", Msg));
568		end procedure;
569		
570		-- -----------------------------------------------------------------------	
571		-- Slave Side Transactions
572		-- -----------------------------------------------------------------------
573		procedure I2cSlaveWaitStart(	signal Scl 	: inout std_logic;
574										signal Sda 	: inout std_logic;
575										Msg			: in 	string		:= "No Msg";
576										Timeout		: in	time		:= 1 ms;
577										Prefix		: in 	string		:= "###ERROR###: ") is
578			constant MsgInfo : MsgInfo_r := (Prefix, "I2cSlaveWaitStart", Msg);
579		begin
580			-- Initial check
581			LevelCheck('1', Scl, MsgInfo, "SCL must be 1 before procedure is called");
582			LevelCheck('1', Sda, MsgInfo, "SDA must be 1 before procedure is called");
583			
584			-- Do start checking
585			LevelWait('0', Sda, Timeout, MsgInfo, "SDA did not go low");
586			LevelCheck('1', Scl, MsgInfo, "SCL must be 1 during SDA falling edge");
587			LevelWait('0', Scl, Timeout, MsgInfo, "SCL did not go low");
588			LevelCheck('0', Sda, MsgInfo, "SDA must be 0 during SCL falling edge");		
589			
590			-- Wait for center of SCL low
591			wait for ClkQuartPeriod;
592		end procedure;
593								
594		procedure I2cSlaveWaitRepeatedStart(	signal Scl 	: inout std_logic;
595												signal Sda 	: inout std_logic;
596												Msg			: in 	string		:= "No Msg";
597												Timeout		: in	time		:= 1 ms;
598												ClkStretch	: in	time		:= 0 ns;	-- hold clock-low for at least this time
599												Prefix		: in 	string	:= "###ERROR###: ") is
600			constant MsgInfo : MsgInfo_r := (Prefix, "I2cSlaveWaitRepeatedStart", Msg);
601		begin
602			-- Initial Check
603			if to_01X(Scl) = '1' then
604				LevelCheck('1', Sda, MsgInfo, "SDA must be 1 before procedure is called if SCL = 1");
605			end if;
606			
607			-- Do Check
608			if to_01X(Scl) = '0' then
609				-- Clock stretching
610				if ClkStretch > 0 ns then
611					Scl <= '0';
612					wait for ClkStretch;
613					Scl <= 'Z';
614				end if;	
615				LevelWait('1', Scl, Timeout, MsgInfo, "SCL did not go high");
616				LevelCheck('1', Sda, MsgInfo, "SDA must be 1 before SCL goes high");
617			end if;
618			LevelWait('0', Sda, Timeout, MsgInfo, "SDA did not go low");
619			LevelCheck('1', Scl, MsgInfo, "SCL must be 1 during SDA falling edge");
620			LevelWait('0', Scl, Timeout, MsgInfo, "SCL did not go low");
621			LevelCheck('0', Sda, MsgInfo, "SDA must be 0 during SCL falling edge");		
622			
623			-- Wait for center of SCL low
624			wait for ClkQuartPeriod;
625		end procedure;
626										
627		procedure I2cSlaveWaitStop(	signal Scl 	: inout std_logic;
628									signal Sda 	: inout std_logic;
629									Msg			: in 	string		:= "No Msg";
630									Timeout		: in	time		:= 1 ms;
631									ClkStretch	: in	time		:= 0 ns;	-- hold clock-low for at least this time
632									Prefix		: in 	string	:= "###ERROR###: ") is
633			constant MsgInfo : MsgInfo_r := (Prefix, "I2cSlaveWaitStop", Msg);
634		begin
635			-- Initial check
636			if to_01X(Scl) = '1' then
637				LevelCheck('0', Sda, MsgInfo, "SDA must be 0 before procedure is called if SCL = 1");
638			end if;
639			
640			-- Do Check
641			if Scl = '0' then
642				-- Clock stretching
643				if ClkStretch > 0 ns then
644					Scl <= '0';
645					wait for ClkStretch;
646					Scl <= 'Z';
647				end if;	
648				LevelWait('1', Scl, Timeout, MsgInfo, "SCL did not go high");
649				LevelCheck('0', Sda, MsgInfo, "SDA must be 0 before SCL goes high");
650			end if;
651			LevelWait('1', Sda, Timeout, MsgInfo, "SDA did not go high");
652			LevelCheck('1', Scl, MsgInfo, "SCL must be 1 during SDA rising edge");
653			
654			-- Wait for center of SCL low
655			wait for ClkQuartPeriod;
656		end procedure;
657								
658		procedure I2cSlaveExpectAddr(	Address 	: in	integer;
659										IsRead		: in	boolean;
660										signal Scl	: inout std_logic;
661										signal Sda	: inout std_logic;
662										Msg			: in 	string		:= "No Msg";
663										AddrBits	: in	integer		:= 7;		-- 7 or 10
664										AckOutput	: in 	std_logic	:= '0';		-- '0' for ack, '1' for nack
665										Timeout		: in	time		:= 1 ms;
666										ClkStretch	: in	time		:= 0 ns;	-- hold clock-low for at least this time
667										Prefix		: in 	string		:= "###ERROR###: ") is
668			constant AddrSlv_c 	: std_logic_vector(9 downto 0) := std_logic_vector(to_unsigned(Address, 10));
669			constant Rw_c 		: std_logic		:= choose(IsRead, '1', '0');
670		begin
671			-- 7 Bit addressing
672			if AddrBits = 7 then
673				ExpectByteExclClock(AddrSlv_c(6 downto 0) & Rw_c, Scl, Sda, (Prefix, "I2cSlaveExpectAddr 7b", Msg), Timeout, ClkStretch);
674				SendBitExclClock(AckOutput, Scl, Sda, Timeout, "ACK", (Prefix, "I2cSlaveExpectAddr 7b ack", Msg), ClkStretch);
675				I2cBusFree(Scl, Sda);
676			-- 10 Bit addressing
677			elsif AddrBits = 10 then
678				ExpectByteExclClock("11110" & AddrSlv_c(9 downto 8) & Rw_c, Scl, Sda, (Prefix, "I2cSlaveExpectAddr 10b 9:8" , Msg), Timeout, ClkStretch);
679				SendBitExclClock(AckOutput, Scl, Sda, Timeout, "ACK", (Prefix, "I2cSlaveExpectAddr 10b 9:8 ack", Msg), ClkStretch);
680				I2cBusFree(Scl, Sda);
681				ExpectByteExclClock(AddrSlv_c(7 downto 0), Scl, Sda, (Prefix, "I2cSlaveExpectAddr 10b 7:0", Msg), Timeout, ClkStretch);
682				SendBitExclClock(AckOutput, Scl, Sda, Timeout, "ACK", (Prefix, "I2cSlaveExpectAddr 10b 7:0 ack", Msg), ClkStretch);		
683				I2cBusFree(Scl, Sda);
684			else
685				report Prefix & "I2cSlaveExpectAddr - Illegal addrBits (must be 7 or 10) - " & Msg severity error;
686			end if;
687		end procedure;
688									
689		procedure I2cSlaveExpectByte(	ExpData 	: in	integer range -128 to 255;
690										signal Scl	: inout std_logic;
691										signal Sda	: inout std_logic;
692										Msg			: in 	string		:= "No Msg";
693										AckOutput	: in 	std_logic	:= '0';		-- '0' for ack, '1' for nack
694										Timeout		: in	time		:= 1 ms;
695										ClkStretch	: in	time		:= 0 ns;	-- hold clock-low for at least this time
696										Prefix		: in 	string		:= "###ERROR###: ") is
697			variable Data_v : std_logic_vector(7 downto 0);
698		begin
699			if ExpData < 0 then
700				Data_v := std_logic_vector(to_signed(ExpData, 8));
701			else
702				Data_v := std_logic_vector(to_unsigned(ExpData, 8));
703			end if;
704			ExpectByteExclClock(Data_v, Scl, Sda, (Prefix, "I2cSlaveExpectByte", Msg), Timeout, ClkStretch);
705			SendBitExclClock(AckOutput, Scl, Sda, Timeout, "ACK", (Prefix, "I2cSlaveExpectByte ack", Msg), ClkStretch);
706			I2cBusFree(Scl, Sda);
707		end procedure;
708								
709									
710		procedure I2cSlaveSendByte(	Data		: in	integer range -128 to 255;
711									signal Scl	: inout std_logic;
712									signal Sda	: inout std_logic;
713									Msg			: in 	string		:= "No Msg";
714									ExpectedAck	: in 	std_logic	:= '0';			-- '0' for ack, '1' for nack, anything else for "don't check"
715									Timeout		: in	time		:= 1 ms;
716									ClkStretch	: in	time		:= 0 ns;	-- hold clock-low for at least this time
717									Prefix		: in 	string		:= "###ERROR###: ") is
718			variable Data_v : std_logic_vector(7 downto 0);
719		begin
720			-- Convert Data
721			if Data < 0 then
722				Data_v := std_logic_vector(to_signed(Data, 8));
723			else
724				Data_v := std_logic_vector(to_unsigned(Data, 8));
725			end if;
726			
727			-- Send data
728			for i in 7 downto 0 loop
729				SendBitExclClock(Data_v(i), Scl, Sda, Timeout, to_string(i), (Prefix, "I2cSlaveSendByte", Msg), ClkStretch);
730			end loop;
731			
732			-- Check ack
733			I2cBusFree(Scl, Sda);
734			CheckBitExclClock(ExpectedAck, Scl, Sda, Timeout, "ACK", (Prefix, "I2cSlaveSendByte", Msg), ClkStretch);
735					
736		end procedure;
737	
738		
739	end psi_tb_i2c_pkg;
740	
741

