6	
7	------------------------------------------------------------------------------
8	-- Libraries
9	------------------------------------------------------------------------------
10	library ieee;
11		use ieee.std_logic_1164.all;
12		use ieee.numeric_std.all;
13	
14	library work;
15		use work.psi_tb_i2c_pkg.all;
16		use work.psi_tb_txt_util.all;
17	
18	------------------------------------------------------------------------------
19	-- Entity
20	------------------------------------------------------------------------------
21	entity psi_tb_i2c_pkg_tb is
22	end entity;	
23	
24	------------------------------------------------------------------------------
25	-- Architecture Declaration
26	------------------------------------------------------------------------------
27	architecture sim of psi_tb_i2c_pkg_tb is
28		signal scl 	: std_logic := 'H';
29		signal sda	: std_logic := 'H';
30		
31	begin
32		-- Pullup resistors
33		I2cPullup(scl, sda);
34		
35		-- Master Process
36		p_master : process
37		begin
38			-- Setup
39			I2cBusFree(scl, sda);
40			I2cSetFrequency(400.0e3);
41			wait for 1 us;
42			
43			-- *** Addressing ***
44			print(">> Addressing");
45			
46			-- Do 7b address cycle without data, ACK, read
47			print("Do 7b address cycle without data, ACK, read");
48			I2cMasterSendStart(scl, sda, "M: 7b start");
49			I2cMasterSendAddr(16#12#, true, scl, sda, "M: 7b address", 7);
50			I2cMasterSendStop(scl, sda, "M: 7b stop");
51			wait for 10 us;
52			
53			-- Do 7b address cycle without data, ACK, write
54			print("Do 7b address cycle without data, ACK, write");
55			I2cMasterSendStart(scl, sda, "M: 7b start");
56			I2cMasterSendAddr(16#13#, false, scl, sda, "M: 7b address", 7);
57			I2cMasterSendStop(scl, sda, "M: 7b stop");
58			wait for 10 us;
59			
60			-- Do 7b address cycle without data, NACK, read
61			print("Do 7b address cycle without data, NACK, read");
62			I2cMasterSendStart(scl, sda, "M: 7b start");
63			I2cMasterSendAddr(16#12#, true, scl, sda, "M: 7b address", 7, '1');
64			I2cMasterSendStop(scl, sda, "M: 7b stop");
65			wait for 10 us;
66			
67			-- Do 10b address cycle without data, ACK, write
68			print("Do 10b address cycle without data, ACK, write");
69			I2cMasterSendStart(scl, sda, "M: 10b start");
70			I2cMasterSendAddr(16#113#, false, scl, sda, "M: 10b address", 10);
71			I2cMasterSendStop(scl, sda, "M: 10b stop");
72			wait for 10 us;
73			
74			-- Do 10b address cycle without data, NACK, read
75			print("Do 10b address cycle without data, NACK, read");
76			I2cMasterSendStart(scl, sda, "M: 10b start");
77			I2cMasterSendAddr(16#112#, true, scl, sda, "M: 7b address", 10, '1');
78			I2cMasterSendStop(scl, sda, "M: 10b stop");
79			wait for 10 us;
80			
81			-- *** Data Transfers ***
82			print(">> Data Transfers");
83			
84			-- Single Byte Read, ACK
85			print("Single Byte Read, ACK");
86			I2cMasterSendStart(scl, sda, "M: start");
87			I2cMasterSendAddr(16#13#, true, scl, sda, "M: address", 7);
88			I2cMasterExpectByte(16#AB#, scl, sda, "M: data-read");
89			I2cMasterSendStop(scl, sda, "M: stop");
90			wait for 10 us;
91			
92			-- Single Byte Read, NACK
93			print("Single Byte Read, NACK");
94			I2cMasterSendStart(scl, sda, "M: start");
95			I2cMasterSendAddr(16#13#, true, scl, sda, "M: address", 7);
96			I2cMasterExpectByte(16#AB#, scl, sda, "M: data-read", '1');
97			I2cMasterSendStop(scl, sda, "M: stop");
98			wait for 10 us;
99			
100			-- Two Byte Read
101			print("Two Byte Read");
102			I2cMasterSendStart(scl, sda, "M: start");
103			I2cMasterSendAddr(16#13#, true, scl, sda, "M: address", 7);
104			I2cMasterExpectByte(16#AB#, scl, sda, "M: data-read");
105			I2cMasterExpectByte(16#CD#, scl, sda, "M: data-read", '1');
106			I2cMasterSendStop(scl, sda, "M: stop");
107			wait for 10 us;
108			
109			-- Single Byte Write, ACK
110			print("Single Byte Write, ACK");
111			I2cMasterSendStart(scl, sda, "M: start");
